import{c as n,Q as t,j as s,m as e}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"数据工程系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../dataEngineering/00-写作计划.md","filePath":"../dataEngineering/00-写作计划.md","lastUpdated":1778496697000}'),i={name:"../dataEngineering/00-写作计划.md"};function l(r,a,o,p,d,c){return t(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="数据工程系列写作计划" tabindex="-1">数据工程系列写作计划 <a class="header-anchor" href="#数据工程系列写作计划" aria-label="Permalink to &quot;数据工程系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」第 J 项,⭐⭐⭐。 backendLearning 教了「<strong>怎么用数据库 / 缓存 / 搜索引擎</strong>」,aiLearning 零散提过 RAG 的数据预处理,但都没回答一个核心问题:<strong>数据从生产到消费的整条管道,工程师怎么搭</strong>。 <strong>看完这层,你能在白板前画出一家公司从埋点 / Binlog 到 BI 报表 + 推荐召回 + RAG 召回的完整数据链路</strong>——Spark / Flink / Airflow / dbt / Iceberg 不再是&quot;听过的名词&quot;,而是知道每个环节解决什么问题、什么时候上、什么时候过度设计。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「心智」到「AI 时代」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 范式(OLTP vs OLAP / ETL vs ELT / Lambda vs Kappa / 模式演进)</span></span>
<span class="line"><span>   → 存储与表格式(列存 / Parquet / Iceberg / Hudi / Delta / Lakehouse)</span></span>
<span class="line"><span>   → 批处理(Spark 三套 API / Shuffle / AQE / 调优)</span></span>
<span class="line"><span>   → 流处理(Flink / Watermark / Exactly-once / 状态后端 / Kafka)</span></span>
<span class="line"><span>   → 编排与建模(Airflow / Dagster / dbt / 维度建模 / Data Vault)</span></span>
<span class="line"><span>   → AI 时代数据工程(向量库 / 特征平台 / RAG 管道 / 数据质量)</span></span></code></pre></div><p><strong>这个系列不是 Hadoop 教程</strong>——Hadoop 那套以 MapReduce 为中心的世界已经过去,<strong>本系列默认你站在 2025 之后</strong>:对象存储 + 开放表格式 + 计算引擎解耦,Spark / Flink 是主力,Iceberg / dbt 是新约,向量库是 AI 时代的新增成员。</p><p>不深入到引擎源码,<strong>而是讲清楚&quot;数据工程师 / AI 工程师 / 后端工程师能看懂、要会用的图景&quot;</strong>——你写埋点、写离线任务、写实时大屏、写 RAG 检索,这些都站在数据管道上。</p><hr><h2 id="篇目-32-篇" tabindex="-1">篇目(32 篇) <a class="header-anchor" href="#篇目-32-篇" aria-label="Permalink to &quot;篇目(32 篇)&quot;">​</a></h2><h3 id="第一层-心智与范式-01-05" tabindex="-1">第一层:心智与范式(01-05) <a class="header-anchor" href="#第一层-心智与范式-01-05" aria-label="Permalink to &quot;第一层:心智与范式(01-05)&quot;">​</a></h3><ul><li>[ ] 01 数据工程总览(数据从哪来到哪去 / 现代数据栈一张图)</li><li>[ ] 02 OLTP vs OLAP(行存 vs 列存 / 事务 vs 分析 / 为什么要分开)</li><li>[ ] 03 ETL vs ELT(数据仓库时代 vs 数据湖时代 / 谁来做转换)</li><li>[ ] 04 Lambda 与 Kappa(批流分离 vs 批流一体 / 现实是混合架构)</li><li>[ ] 05 模式演进与数据契约(Schema Evolution / Data Contract / Avro / Protobuf)</li></ul><h3 id="第二层-存储与表格式-06-11" tabindex="-1">第二层:存储与表格式(06-11) <a class="header-anchor" href="#第二层-存储与表格式-06-11" aria-label="Permalink to &quot;第二层:存储与表格式(06-11)&quot;">​</a></h3><ul><li>[ ] 06 列存原理(Parquet / ORC / 编码 / 压缩 / 谓词下推)</li><li>[ ] 07 对象存储与数据湖(S3 / OSS / HDFS 退场 / 文件 vs 表)</li><li>[ ] 08 Iceberg 心智(快照 / 分区演进 / 时间旅行 / Hidden Partitioning)</li><li>[ ] 09 Hudi 与 Delta Lake(三剑客对比 / CDC / MoR vs CoW)</li><li>[ ] 10 Lakehouse 架构(湖仓一体 / 为什么不是数据仓库 2.0)</li><li>[ ] 11 Catalog 与元数据(Hive Metastore / Glue / Nessie / Unity)</li></ul><h3 id="第三层-批处理-12-16" tabindex="-1">第三层:批处理(12-16) <a class="header-anchor" href="#第三层-批处理-12-16" aria-label="Permalink to &quot;第三层:批处理(12-16)&quot;">​</a></h3><ul><li>[ ] 12 Spark 心智(RDD / DataFrame / Spark SQL / Catalyst)</li><li>[ ] 13 Spark 执行模型(Job / Stage / Task / Shuffle / 宽窄依赖)</li><li>[ ] 14 Spark 调优(分区 / 倾斜 / 广播 / 持久化 / 序列化)</li><li>[ ] 15 AQE 与现代 Spark(Adaptive Query Execution / Dynamic Partition Pruning)</li><li>[ ] 16 批处理替代品(Trino / Presto / DuckDB / 哪种场景选哪个)</li></ul><h3 id="第四层-流处理-17-22" tabindex="-1">第四层:流处理(17-22) <a class="header-anchor" href="#第四层-流处理-17-22" aria-label="Permalink to &quot;第四层:流处理(17-22)&quot;">​</a></h3><ul><li>[ ] 17 Kafka 在数据管道里的位置(Topic / Partition / Log Compaction / 不是消息队列)</li><li>[ ] 18 流处理心智(时间 / 窗口 / 状态 / 一次 vs 至少一次 vs 精确一次)</li><li>[ ] 19 Watermark 与乱序(事件时间 / 水位线 / Late Event / Allowed Lateness)</li><li>[ ] 20 Flink 架构(JobManager / TaskManager / Checkpoint / Savepoint)</li><li>[ ] 21 Flink 状态后端(RocksDB / 增量 Checkpoint / 状态 TTL)</li><li>[ ] 22 流批一体的真相(Flink SQL / Spark Structured Streaming / 工程选型)</li></ul><h3 id="第五层-编排与建模-23-27" tabindex="-1">第五层:编排与建模(23-27) <a class="header-anchor" href="#第五层-编排与建模-23-27" aria-label="Permalink to &quot;第五层:编排与建模(23-27)&quot;">​</a></h3><ul><li>[ ] 23 工作流编排(Airflow 心智 / DAG / Operator / Sensor / Scheduler)</li><li>[ ] 24 现代编排器(Dagster / Prefect / 资产化 / 声明式管道)</li><li>[ ] 25 dbt 心智(SQL 即代码 / model / test / 谱系 / 软件工程进数仓)</li><li>[ ] 26 数据建模(维度建模 / 星型 vs 雪花 / 缓慢变化维 / Data Vault)</li><li>[ ] 27 CDC 实战(Debezium / Flink CDC / 增量同步 vs 全量重算)</li></ul><h3 id="第六层-ai-时代数据工程-28-32" tabindex="-1">第六层:AI 时代数据工程(28-32) <a class="header-anchor" href="#第六层-ai-时代数据工程-28-32" aria-label="Permalink to &quot;第六层:AI 时代数据工程(28-32)&quot;">​</a></h3><ul><li>[ ] 28 向量数据库(pgvector / Milvus / Weaviate / 索引 / 选型)</li><li>[ ] 29 RAG 数据管道(切片 / 嵌入 / 索引 / 增量更新 / 评测回路)</li><li>[ ] 30 特征平台(Feature Store / 离线特征 / 在线特征 / 训练-服务一致性)</li><li>[ ] 31 数据质量与可观测(Great Expectations / Soda / dbt test / 数据 SLA)</li><li>[ ] 32 数据工程的未来(开放表格式之争 / 计算存储分离 / AI 改写数据栈)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>SQL / 索引 / 事务</td><td>backendLearning ✅</td><td>不重复,只讲分析型 SQL 与列存执行(06、12-16)</td></tr><tr><td>Redis / 缓存</td><td>backendLearning ✅</td><td>不重复</td></tr><tr><td>Elasticsearch / 倒排索引</td><td>backendLearning ✅</td><td>不重复,只在 28 提向量与倒排互补</td></tr><tr><td>消息队列 / Kafka 基础</td><td>backendLearning ✅</td><td>不重复,17 只讲 Kafka 作为日志在数据管道的位置</td></tr><tr><td>分布式一致性 / 数据迁移</td><td>systemDesign ✅</td><td>不重复,只讲数据管道里的一致性语义</td></tr><tr><td>一致性哈希 / 布隆过滤</td><td>algorithmLearning ✅</td><td>不重复,只在列存/Iceberg 用到时点名</td></tr><tr><td>RAG / Embedding 模型</td><td>aiLearning ✅</td><td>互补,本系列讲&quot;数据管道一侧&quot;,aiLearning 讲&quot;模型一侧&quot;</td></tr><tr><td>K8s / 容器</td><td>backendLearning / osLearning ✅</td><td>不重复,只在引擎部署形态时点名</td></tr><tr><td>网络与序列化协议</td><td>webLearning / networkLearning ✅</td><td>不重复,05 只在数据契约场景讲 Avro/Protobuf</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么这个工具 → 心智模型 → 工程落地 → 替代方案与局限&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么这个工具存在</span></span>
<span class="line"><span>   - 没它的世界长什么样(上一代是谁,死在哪)</span></span>
<span class="line"><span>   - 它解决的根本问题是什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 心智模型(一张图)</span></span>
<span class="line"><span>   - 数据流图 / 时间线图 / 分层图,任选其一</span></span>
<span class="line"><span>   - 关键概念用最少的名词讲清楚</span></span>
<span class="line"><span>   - 不堆术语,术语第一次出现时一句话定义</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程落地</span></span>
<span class="line"><span>   - 最小可跑的一段代码或配置(SQL / Python / YAML)</span></span>
<span class="line"><span>   - 真实场景:这家公司为什么这么用,踩过什么坑</span></span>
<span class="line"><span>   - 调优 / 监控 / 故障排查的关键指标</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 替代方案与局限</span></span>
<span class="line"><span>   - 同代位竞争者(Spark vs Trino / Iceberg vs Hudi / Airflow vs Dagster)</span></span>
<span class="line"><span>   - 什么场景不该用它</span></span>
<span class="line"><span>   - 现在 2025 之后业界往哪个方向走</span></span></code></pre></div><p>不堆官方文档配置项——<strong>只贴关键的 10-30 行代码或 SQL</strong>,让读者「看到一条数据从输入到输出的形状」就够了。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05  心智:看完知道&quot;数据栈每一层在解决什么问题,不会再把数据湖和数据仓库混着说&quot;</span></span>
<span class="line"><span>06-11  存储:看完知道&quot;为什么开放表格式赢了,Iceberg 凭什么是赢家之一&quot;</span></span>
<span class="line"><span>12-16  批处理:**离线场景的硬通货**,Spark 调优是数据工程师面试必答题</span></span>
<span class="line"><span>17-22  流处理:**实时业务的核心**,Flink + Kafka 是新一代数仓的发动机</span></span>
<span class="line"><span>23-27  编排与建模:**软件工程方法进数据**,dbt + Airflow 决定团队上限</span></span>
<span class="line"><span>28-32  AI 时代:**当下最热**,RAG 管道 / 特征平台 / 向量库是 AI 工程化的入口</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 06-11 + 23-27 这 11 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 Parquet 在分析查询能比行存快 10 倍,代价是什么&quot;</li><li>&quot;为什么 Iceberg 在大公司能取代 Hive,小公司直接用 DuckDB 也行&quot;</li><li>&quot;为什么 dbt 让 SQL 终于可以测试 / Code Review / CI,以前为什么不能&quot;</li><li>&quot;为什么 Airflow 写 DAG 还能写出&#39;数据回溯&#39;的 bug,Dagster 怎么解&quot;</li></ul><p>再加上 28-32 这 5 篇,你应该能讲清楚:</p><ul><li>&quot;RAG 的数据管道和传统离线特征管道有什么区别,增量更新怎么做&quot;</li><li>&quot;为什么向量库不会替代搜索引擎,二者怎么混合&quot;</li><li>&quot;特征平台为什么必须管离线和在线两边,训练-服务偏差怎么消&quot;</li></ul><p>能讲清楚两题这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li><strong>不讲 Hadoop / MapReduce 历史</strong>——MapReduce 时代过去了,不讲 HDFS NameNode 高可用,不讲 YARN 调度细节,不讲 Hive on MR;它们只在&quot;上一代死在哪&quot;作为背景出现,一句话带过</li><li>「先讲个大数据起源故事 / Google 三大论文逐一拆解」——直接进重点,论文只在脚注引用</li><li>罗列工具命令 / 配置参数大全——只贴让读者&quot;看懂这一层&quot;的最小配置</li><li>「这是面试常考」——读者来这里是为了真懂数据怎么流,不是背名词</li><li>不画图就讲 Shuffle / Watermark / Checkpoint / 列存——这些东西<strong>不画图永远讲不清楚</strong></li><li>抄官方 Quick Start——官方文档在那儿,这里只补它没讲透的「为什么」和「什么时候不要用」</li><li>「Spark vs Flink 谁更牛」式的口水战——只讲各自擅长的场景,选型留给工程判断</li><li>不区分 OLTP 和 OLAP 就开始讲——所有讨论的前提都是 OLAP / 分析型负载,事务型场景明确划走给 backendLearning</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于工程视角</strong>——能落地、能排错、能选型、能给团队建议。</p><p>所有示例代码限制在最小可跑片段,<strong>不教你怎么从零搭一套 EMR / 自建 K8s Spark 集群</strong>——那是平台团队的事,本系列的读者画像是「写数据管道的应用工程师 / AI 工程师」,你需要懂这些工具,但不需要从内核源码读起。</p>`,46)])])}const g=n(i,[["render",l]]);export{h as __pageData,g as default};
